export interface Photo {
  id: string;
  /** Web-sized image URL (photography/web/ on S3, served via CloudFront). */
  src: string;
  /** Thumbnail URL (max 640px) used by the masonry grid. */
  thumbSrc: string;
  /** Intrinsic pixel dimensions of the web-sized image — prevents layout shift. */
  width: number;
  height: number;
  /** Alt text for accessibility + SEO. Personalize these when you get a chance. */
  alt: string;
  /** Optional short caption/title, shown in the lightbox. */
  caption?: string;
  /** Tiny inlined blur-up preview (LQIP), shown instantly while the photo loads. */
  blurDataURL: string;
}

